diff --git a/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h b/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h
index ee3cc950cdb5..5ffe68bd6da9 100644
--- a/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h
+++ b/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h
@@ -23,7 +23,7 @@ class AssumptionCache;
 struct SimplifyCFGOptions {
   int BonusInstThreshold = 1;
   bool ForwardSwitchCondToPhi = false;
-  bool ConvertSwitchRangeToICmp = false;
+  bool ConvertSwitchRangeToICmp = true;
   bool ConvertSwitchToLookupTable = false;
   bool NeedCanonicalLoop = true;
   bool HoistCommonInsts = false;
diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 48055ad6ea7e..f92b75cd0cc2 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5816,6 +5816,8 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
   SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
   BasicBlock *ContiguousDest = nullptr;
   BasicBlock *OtherDest = nullptr;
+  // This vector holds the complement cases if we need to create them.
+  SmallVector<ConstantInt *, 16> ComplementCases;
   if (!CasesA.empty() && casesAreContiguous(CasesA)) {
     ContiguousCases = &CasesA;
     ContiguousDest = DestA;
@@ -5824,7 +5826,73 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
     ContiguousCases = &CasesB;
     ContiguousDest = DestB;
     OtherDest = DestA;
-  } else
+  } else {
+    // If neither set is contiguous, try to see if the set of values going to
+    // the default destination within the known possible values forms a
+    // contiguous range. This handles cases like {0, 4, 5} with range [0, 6)
+    // where the complement {1, 2, 3} is contiguous.
+    ConstantRange CR = computeConstantRange(
+        SI->getCondition(), /*ForSigned=*/false, /*UseInstrInfo=*/true,
+        Options.AC, SI);
+    if (!CR.isFullSet()) {
+      APInt RangeLow = CR.getLower();
+      APInt RangeHigh = CR.getUpper();
+
+      // Try each destination as the potential "contiguous" destination.
+      for (int Iter = 0; Iter < 2; ++Iter) {
+        SmallVectorImpl<ConstantInt *> &Cases = Iter == 0 ? CasesA : CasesB;
+        BasicBlock *Dest = Iter == 0 ? DestA : DestB;
+        BasicBlock *OtherDst = Iter == 0 ? DestB : DestA;
+
+        // Only the default destination can have implicit (non-case) values.
+        if (Dest != SI->getDefaultDest())
+          continue;
+
+        // Collect all explicit case values.
+        SmallVector<APInt, 16> AllCaseVals;
+        for (const auto &C : SI->cases())
+          AllCaseVals.push_back(C.getCaseValue()->getValue());
+
+        // Sort ascending.
+        llvm::sort(AllCaseVals,
+                   [](const APInt &A, const APInt &B) { return A.ult(B); });
+
+        // Find gaps between case values within the known range.
+        SmallVector<std::pair<APInt, APInt>, 4> Gaps;
+        APInt Cur = RangeLow;
+        for (const APInt &Val : AllCaseVals) {
+          if (Cur.ult(Val))
+            Gaps.push_back({Cur, Val});
+          Cur = Val + 1;
+        }
+        if (Cur.ult(RangeHigh))
+          Gaps.push_back({Cur, RangeHigh});
+
+        // If exactly one gap, it's our complement.
+        if (Gaps.size() == 1) {
+          APInt GapStart = Gaps[0].first;
+          APInt GapEnd = Gaps[0].second;
+
+          IntegerType *Ty = cast<IntegerType>(SI->getCondition()->getType());
+          ComplementCases.clear();
+          for (APInt V = GapStart; V.ult(GapEnd); ++V)
+            ComplementCases.push_back(cast<ConstantInt>(ConstantInt::get(Ty, V)));
+
+          // Sort in the same order as casesAreContiguous does (descending)
+          // so that back() is the minimum value.
+          array_pod_sort(ComplementCases.begin(), ComplementCases.end(),
+                         constantIntSortPredicate);
+
+          ContiguousCases = &ComplementCases;
+          ContiguousDest = Dest;  // The default dest
+          OtherDest = OtherDst;
+          break;
+        }
+      }
+    }
+  }
+
+  if (!ContiguousCases)
     return false;

   // Start building the compare and branch.
@@ -5868,18 +5936,25 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
   }

   // Prune obsolete incoming values off the successors' PHI nodes.
+  // Compute the number of switch edges to each destination.
+  unsigned EdgesToContiguous = 0;
+  unsigned EdgesToOther = 0;
+  for (const auto &Case : SI->cases()) {
+    if (Case.getCaseSuccessor() == ContiguousDest)
+      ++EdgesToContiguous;
+    else if (Case.getCaseSuccessor() == OtherDest)
+      ++EdgesToOther;
+  }
+  if (SI->getDefaultDest() == ContiguousDest)
+    ++EdgesToContiguous;
+  else if (SI->getDefaultDest() == OtherDest)
+    ++EdgesToOther;
   for (auto BBI = ContiguousDest->begin(); isa<PHINode>(BBI); ++BBI) {
-    unsigned PreviousEdges = ContiguousCases->size();
-    if (ContiguousDest == SI->getDefaultDest())
-      ++PreviousEdges;
-    for (unsigned I = 0, E = PreviousEdges - 1; I != E; ++I)
+    for (unsigned I = 0, E = EdgesToContiguous - 1; I != E; ++I)
       cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
   }
   for (auto BBI = OtherDest->begin(); isa<PHINode>(BBI); ++BBI) {
-    unsigned PreviousEdges = SI->getNumCases() - ContiguousCases->size();
-    if (OtherDest == SI->getDefaultDest())
-      ++PreviousEdges;
-    for (unsigned I = 0, E = PreviousEdges - 1; I != E; ++I)
+    for (unsigned I = 0, E = EdgesToOther - 1; I != E; ++I)
       cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
   }

